// // This module implements a 4-bit binary counter with asynchronous reset and disable signals. The counter decrements by 1 on each negative clock edge when disabled, and resets to 15 when reset is deasserted.
module top_module(
	input clk,
	input reset,
	input ena,
	output reg [3:0] q);always @(posedge clk) begin
		if (reset)
			q <= 4'b0;
		else if (ena)
			q <= q + 1;
	end
endmodule
